const interactions = $input.all().map(item => item.json.fields || item.json);
const total = interactions.length;

// By agent — compute total, avg_response_ms, error_count per agent
const agentData = {};
interactions.forEach(i => {
  const agent = i.agent || 'unknown';
  if (!agentData[agent]) agentData[agent] = { total: 0, times: [], errors: 0 };
  agentData[agent].total++;
  const ms = parseInt(i.response_time_ms) || 0;
  if (ms > 0) agentData[agent].times.push(ms);
  if (i.status === 'error') agentData[agent].errors++;
});

const byAgent = {};
for (const [agent, d] of Object.entries(agentData)) {
  byAgent[agent] = {
    total: d.total,
    avg_response_ms: d.times.length > 0 ? Math.round(d.times.reduce((a, b) => a + b, 0) / d.times.length) : 0,
    error_count: d.errors
  };
}

// Avg response time (global)
const allTimes = interactions.map(i => parseInt(i.response_time_ms) || 0).filter(t => t > 0);
const avgResponseMs = allTimes.length > 0 ? Math.round(allTimes.reduce((a, b) => a + b, 0) / allTimes.length) : 0;

// Error rate
const errors = interactions.filter(i => i.status === 'error').length;
const errorRate = total > 0 ? parseFloat((errors / total).toFixed(4)) : 0;

// Peak hour
const hourCounts = {};
interactions.forEach(i => {
  if (i.created_at) {
    try {
      const hour = new Date(i.created_at).getHours();
      hourCounts[hour] = (hourCounts[hour] || 0) + 1;
    } catch (e) {}
  }
});
const peakHour = Object.keys(hourCounts).length > 0 ? parseInt(Object.entries(hourCounts).sort((a, b) => b[1] - a[1])[0][0]) : 0;

// Top document
const docMentions = {};
interactions.forEach(i => {
  if (i.agent === 'docmentor' && i.input_preview) {
    const key = i.input_preview.slice(0, 80);
    docMentions[key] = (docMentions[key] || 0) + 1;
  }
});
const topDocument = Object.keys(docMentions).length > 0 ? Object.entries(docMentions).sort((a, b) => b[1] - a[1])[0][0] : '';

return [{
  json: {
    period: 'hourly',
    total_interactions: total,
    by_agent: JSON.stringify(byAgent),
    avg_response_ms: avgResponseMs,
    error_rate: errorRate,
    peak_hour: peakHour,
    top_document: topDocument
  }
}];

const items = $input.all();
const interactions = items.map(item => item.json.fields || item.json);

// Get time range from webhook query
let range = 'all';
try {
  const webhookData = $('GET /analytics/summary').first().json;
  range = webhookData.query?.range || webhookData.body?.range || 'all';
} catch(e) {}

const now = new Date();
let cutoff = null;
if (range === '7d') cutoff = new Date(now - 7 * 24 * 60 * 60 * 1000);
else if (range === '30d') cutoff = new Date(now - 30 * 24 * 60 * 60 * 1000);

const filtered = cutoff
  ? interactions.filter(i => {
      const d = new Date(i.created_at || i.Created || 0);
      return d >= cutoff;
    })
  : interactions;

const total = filtered.length;

// By agent
const agentData = {};
filtered.forEach(i => {
  const agent = i.agent || 'unknown';
  if (!agentData[agent]) agentData[agent] = { total: 0, times: [], errors: 0 };
  agentData[agent].total++;
  const ms = parseInt(i.response_time_ms) || 0;
  if (ms > 0 && ms < 300000) agentData[agent].times.push(ms);
  if (i.status === 'error') agentData[agent].errors++;
});

const byAgent = {};
for (const [agent, d] of Object.entries(agentData)) {
  byAgent[agent] = {
    total: d.total,
    avg_response_ms: d.times.length > 0 ? Math.round(d.times.reduce((a, b) => a + b, 0) / d.times.length) : 0,
    error_count: d.errors
  };
}

// Global avg response
const allTimes = filtered.map(i => parseInt(i.response_time_ms) || 0).filter(t => t > 0 && t < 300000);
const avgResponseMs = allTimes.length > 0 ? Math.round(allTimes.reduce((a, b) => a + b, 0) / allTimes.length) : 0;

// Error rate
const errors = filtered.filter(i => i.status === 'error').length;
const errorRate = total > 0 ? parseFloat((errors / total).toFixed(4)) : 0;

// Recent activity - group by date
const dayCounts = {};
filtered.forEach(i => {
  const d = i.created_at || i.Created;
  if (d) {
    try {
      const date = new Date(d);
      const key = date.toISOString().split('T')[0];
      dayCounts[key] = (dayCounts[key] || 0) + 1;
    } catch(e) {}
  }
});

const recentActivity = [];
const days = range === '7d' ? 7 : range === '30d' ? 30 : 14;
for (let i = days - 1; i >= 0; i--) {
  const d = new Date(now);
  d.setDate(d.getDate() - i);
  const key = d.toISOString().split('T')[0];
  const label = d.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
  recentActivity.push({ date: label, count: dayCounts[key] || 0 });
}

// Top queries
const queryCounts = {};
filtered.forEach(i => {
  const q = (i.input_preview || '').trim();
  if (q && q.length > 3) {
    const normalized = q.slice(0, 80);
    queryCounts[normalized] = (queryCounts[normalized] || 0) + 1;
  }
});
const topQueries = Object.entries(queryCounts)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 10)
  .map(([query, count]) => ({ query, count }));

return [{
  json: {
    total_interactions: total,
    by_agent: byAgent,
    avg_response_ms: avgResponseMs,
    error_rate: errorRate,
    recent_activity: recentActivity,
    top_queries: topQueries,
  }
}];

// Get the analytics computed earlier
const analytics = $('Compute Fresh Analytics').first().json;

// Get documents from current input
const docItems = $input.all();
const docs = docItems.map(item => item.json.fields || item.json);
const totalDocs = docs.length;
const totalChunks = docs.reduce((sum, d) => sum + (parseInt(d.chunk_count) || parseInt(d.chunks) || 0), 0);

return [{
  json: {
    ...analytics,
    total_documents: totalDocs,
    total_chunks: totalChunks
  }
}];

